#include<bits/stdc++.h>
using namespace std;
struct node{
	int a[4];
}p[100005];


int main()
{
	int t;
	cin >> t;

	while(t--){
		int n;
		cin >> n;
        int ans = 0;
        vector<pair<int, int> >v[4];
        int cnt[4] = {0, 0, 0, 0};
		for(int i = 1; i <= n; i++){
			int a, b, c;
			cin >> a >> b >> c;
			p[i].a[1] = a;
			p[i].a[2] = b;
			p[i].a[3] = c;
			int x = max(a, max(b, c));
			if(a == x){
				cnt[1]++;
				v[1].push_back({min(a - b, a - c), i});
				ans += a;
			}
			else if(b == x){
				cnt[2]++;
				v[2].push_back({min(b - a, b - c), i});
				ans += b;
			}
			else {
				cnt[3]++;
				v[3].push_back({min(c - a, c - b), i});
				ans += c;
			}
		}
		for(int i = 1; i <= 3; i++){
			if(cnt[i] > n / 2){
				sort(v[i].begin(), v[i].end());
				int x = cnt[i] - n / 2;
				for(int j = 0; j < x; j++){
					ans -= v[i][j].first;
				}
				break;
			}
		}
		cout << ans << endl;
	}
}
